/** Flutter/Dart flashcard deck, keyed by topic id — 5 cards per topic, 62 topics. */
export const FLUTTER_FLASHCARDS: FlashcardData = {
  'flutter-intro': [
    { id: 'fi_1', q: 'How does Flutter differ architecturally from React Native?', a: 'React Native bridges JavaScript to native platform widgets (serialization overhead, platform-specific look). Flutter renders every pixel itself with its own engine (Impeller/Skia) — no bridge, identical UI on every platform, native-compiled Dart.' },
    { id: 'fi_2', q: 'What is the difference between JIT and AOT compilation in Flutter?', a: 'Debug builds use JIT (Just-In-Time): code compiles while running, enabling hot reload. Release builds use AOT (Ahead-Of-Time): Dart compiles to native ARM/x64 machine code for maximum performance.' },
    { id: 'fi_3', q: 'How does hot reload work?', a: 'New code is injected into the running Dart VM and the widget tree rebuilds — preserving app state. Limits: changes to main(), initState logic, or enum/class structure may need a hot restart (R) which resets state.' },
    { id: 'fi_4', q: 'When is Flutter the WRONG choice?', a: 'Content-heavy SEO websites (canvas rendering is search-engine hostile), apps needing brand-new platform APIs on day one, and very thin apps where a webview suffices. Also weigh team skills: an all-Swift team may ship native faster.' },
    { id: 'fi_5', q: "Name the layers of Flutter's architecture.", a: "Your Dart app code → Flutter framework (widgets, rendering, animation — written in Dart) → Flutter engine (C++: Impeller graphics, text layout, Dart runtime) → platform embedder (iOS/Android/web/desktop glue)." },
  ],
  'dev-environment': [
    { id: 'de_1', q: 'What does flutter doctor do?', a: 'Diagnoses your toolchain: Flutter SDK, Android toolchain/licenses, Xcode (Mac), connected devices, and IDE plugins. Each ✗ comes with fix instructions — resolve all of them before building.' },
    { id: 'de_2', q: 'Why use FVM (Flutter Version Management)?', a: "It pins an exact Flutter version per project so every team member and CI build with identical toolchains — eliminating \"works on my machine\" from version drift. Essential when maintaining multiple apps." },
    { id: 'de_3', q: 'APK vs App Bundle (AAB) — difference?', a: 'APK is a complete installable package (universal, larger). AAB is an upload format: Google Play generates optimized per-device APKs from it (smaller downloads). Play Store requires AAB for new apps.' },
    { id: 'de_4', q: 'Why register developer accounts early?', a: 'Apple Developer ($99/yr) and Google Play ($25 once) both have identity verification that can take days. Registering early means verification never blocks your release week.' },
    { id: 'de_5', q: 'What is DartPad?', a: 'A zero-install browser playground (dartpad.dev) for running Dart and simple Flutter code instantly — the fastest way to experiment with language features without creating a project.' },
  ],
  'dart-basics': [
    { id: 'db_1', q: 'final vs const in Dart?', a: 'final = assigned once at runtime (final now = DateTime.now() is fine). const = compile-time constant, deeply immutable and canonicalized (const pi = 3.14). const requires the value to be known at compile time.' },
    { id: 'db_2', q: "What does it mean that Dart's type system is \"sound\"?", a: 'If the compiler accepts a value as type T, it IS a T at runtime — no surprises. This lets the compiler optimize aggressively and eliminates whole classes of runtime type errors.' },
    { id: 'db_3', q: 'How do named parameters work?', a: "Declared in braces: greet({required String name, String greeting = 'Hello'}). Callers pass by name: greet(name: 'Faiz'). required marks mandatory ones; others need defaults or nullable types." },
    { id: 'db_4', q: 'What does 5 / 2 return in Dart? And 5 ~/ 2?', a: '5 / 2 returns 2.5 — the / operator ALWAYS returns double. 5 ~/ 2 returns 2 — ~/ is integer (truncating) division.' },
    { id: 'db_5', q: 'String interpolation: $name vs ${expression}?', a: '$name embeds a simple variable. ${} is needed for expressions: "Sum: ${a + b}" or "Name: ${user.name}" — without braces, "$user.name" prints the user object then literal ".name".' },
  ],
  'dart-control-flow': [
    { id: 'dcf_1', q: 'What does the ?? operator do?', a: "Null-coalescing: returns the left side if non-null, otherwise the right. final display = nickname ?? 'Anonymous'. Sibling ??= assigns only if currently null." },
    { id: 'dcf_2', q: 'Why are switch expressions over sealed classes powerful?', a: 'The compiler checks exhaustiveness: if you add a new state subclass and forget to handle it in a switch, you get a compile ERROR, not a runtime bug. Impossible to forget a UI state.' },
    { id: 'dcf_3', q: 'What is collection-if / collection-for?', a: 'if and for directly inside list literals: [Home, if (isAdmin) AdminPanel, for (final p in plugins) PluginTile(p)] — the idiomatic way to build conditional widget lists declaratively.' },
    { id: 'dcf_4', q: 'What does the cascade operator (..) do?', a: 'Calls multiple members on the same object without repeating it: controller..addListener(fn)..forward(). Returns the original object, not the method results.' },
    { id: 'dcf_5', q: 'What is a guard clause in a switch pattern?', a: "A when condition on a case: case Loaded(:final items) when items.isEmpty => 'Empty'. The case only matches if both the pattern AND the guard hold." },
  ],
  'dart-collections': [
    { id: 'dco_1', q: 'Why does .map() sometimes "not work" in widget lists?', a: 'map() returns a LAZY Iterable — nothing executes until consumed. Widget children need a real list: notes.map(buildTile).toList(). Forgetting .toList() is a classic silent bug.' },
    { id: 'dco_2', q: 'Why must you copy lists instead of mutating them in state management?', a: 'BLoC/Provider detect changes by comparing old vs new state. In-place mutation makes old == new (same object), so no rebuild fires. Emit copies: [...state.items, newItem].' },
    { id: 'dco_3', q: 'When is a Set better than a List?', a: "For uniqueness and membership checks: Set.contains() is O(1) vs List's O(n), and Sets refuse duplicates automatically — perfect for selected IDs, tags, seen items." },
    { id: 'dco_4', q: 'What are Records in Dart 3?', a: 'Lightweight anonymous tuples: (int, String) positional or ({double total, int count}) named — return multiple values from a function without declaring a class. Destructure with final (a, b) = fn().' },
    { id: 'dco_5', q: 'What does fold do?', a: 'Aggregates a collection into one value with an initial seed: cart.fold<double>(0, (sum, item) => sum + item.price). Like reduce, but the result type can differ from the element type.' },
  ],
  'dart-null-safety': [
    { id: 'dns_1', q: "What makes Dart's null safety \"sound\"?", a: 'Non-nullable types can NEVER hold null — guaranteed at compile time and trusted at runtime (no re-checks needed, enabling optimizations). Nullable types are explicit: String? can be null, String cannot.' },
    { id: 'dns_2', q: 'When is the ! operator acceptable?', a: "Rarely — only when you have an invariant the compiler can't see, ideally with a comment explaining it. Every ! is a potential runtime crash; prefer ??, ?., or restructuring so null is impossible." },
    { id: 'dns_3', q: "Why doesn't type promotion work on class fields?", a: "Another method (or another isolate) could mutate the field between your null check and use — the compiler can't guarantee it stays non-null. Fix: copy to a local variable first, which CAN promote." },
    { id: 'dns_4', q: "What does late do and what's the risk?", a: 'Defers initialization of a non-nullable field (late final controller — set in initState). Risk: using it before assignment throws LateInitializationError at runtime — late is a promise YOU keep, not the compiler.' },
    { id: 'dns_5', q: "What's wrong with user!.profile!.avatar!?", a: 'Any null in the chain crashes the app. Use safe navigation with a fallback: user?.profile?.avatar ?? defaultAvatar — handles every null gracefully in one expression.' },
  ],
  'dart-oop': [
    { id: 'do_1', q: 'What is a factory constructor used for?', a: 'A constructor that can return cached instances, subtypes, or computed objects — not always a fresh instance. The two key patterns: Model.fromJson(json) for API parsing, and singletons (factory Db() => _instance).' },
    { id: 'do_2', q: 'Why do const constructors improve Flutter performance?', a: "const widgets are canonicalized compile-time constants — during rebuilds, Flutter's diff sees the identical instance and SKIPS the entire subtree. Free performance in lists and frequently-rebuilt parents." },
    { id: 'do_3', q: 'extends vs implements vs with?', a: 'extends: single inheritance, inherits implementation. implements: treats a class as an interface — you must reimplement EVERY member. with: applies mixins — injects reusable behavior without inheritance.' },
    { id: 'do_4', q: 'Why override == and hashCode on data classes?', a: "Default equality is identity (same object). Without value equality, two Notes with identical data aren't equal — state comparisons fail, Sets hold duplicates, BLoC can't dedupe states. Use Equatable or freezed to generate it." },
    { id: 'do_5', q: 'What can enhanced enums do (Dart 2.17+)?', a: 'Hold fields, constructors, methods, and getters: enum Plan { free(0), pro(9.99); final double price; const Plan(this.price); bool get isPaid => price > 0; } — type-safe value objects.' },
  ],
  'dart-advanced': [
    { id: 'da_1', q: 'What problem do generics solve?', a: "Type-safe reuse: Future<T>, List<Note>, Result<User> — one class working with any type while the compiler enforces correctness. Without them you'd cast from dynamic everywhere and find errors at runtime." },
    { id: 'da_2', q: 'Mixin vs abstract class?', a: 'A mixin injects reusable behavior into ANY class (with Logging) without consuming the single extends slot; multiple mixins compose. An abstract class defines a contract/partial implementation requiring inheritance.' },
    { id: 'da_3', q: 'What are extension methods?', a: "Add capabilities to types you don't own: extension on BuildContext { ThemeData get theme => Theme.of(this); } — then context.theme works everywhere. The standard trick for context shortcuts." },
    { id: 'da_4', q: 'What does sealed give you over abstract?', a: "A sealed class's subtypes are all known to the compiler (same library) — switch statements over them are exhaustiveness-checked. The foundation of compile-safe state modeling." },
    { id: 'da_5', q: 'What happens with conflicting mixins: class A with B, C?', a: "Later wins: C's implementation overrides B's for any conflicting members. Mixin order is a real semantic choice, not style." },
  ],
  'dart-async': [
    { id: 'das_1', q: 'Dart is single-threaded — how does it handle concurrent network calls?', a: 'The I/O happens outside the Dart thread (OS/event sources); await yields control so the event loop keeps processing (UI keeps painting) until the result arrives. Concurrency through cooperative yielding, not threads.' },
    { id: 'das_2', q: 'Future vs Stream?', a: 'Future: ONE value (or error), later — an API call. Stream: MANY values over time — Firestore snapshots, auth changes, user taps. async/await for futures; await for / listen for streams.' },
    { id: 'das_3', q: 'When do you need an isolate?', a: "Only for CPU-heavy work (parsing huge JSON, image processing, crypto) that would block the event loop and jank the UI. Network waits do NOT need isolates — they don't occupy the thread." },
    { id: 'das_4', q: 'Single-subscription vs broadcast stream?', a: 'Single-subscription (default): one listener, buffered, consumed once. Broadcast: many simultaneous listeners, events missed if not listening. UI streams shared by multiple widgets need broadcast (or BehaviorSubject).' },
    { id: 'das_5', q: 'Why check mounted before setState after an await?', a: 'The widget may have been disposed while awaiting (user navigated away). setState on a disposed State throws. Guard: if (mounted) setState(...). The use_build_context_synchronously lint catches the context version.' },
  ],
  'flutter-project-setup': [
    { id: 'fps_1', q: 'What lives in pubspec.yaml?', a: 'dependencies (runtime packages), dev_dependencies (tests, codegen, lints), and flutter: config — asset and font declarations. Every bundled asset MUST be declared here or it won\'t ship.' },
    { id: 'fps_2', q: 'Why commit pubspec.lock in an app but not a package?', a: 'Apps: the lock pins exact dependency versions so every dev and CI build identically — reproducibility. Packages: consumers resolve their own versions; a lock would be ignored and misleading.' },
    { id: 'fps_3', q: 'Feature-first vs layer-first project structure?', a: 'Layer-first (screens/, services/) scatters one feature across folders. Feature-first (features/auth/{presentation,logic,data}) keeps code that changes together, together — scales to teams and stays navigable.' },
    { id: 'fps_4', q: 'How do you keep secrets out of a Flutter app?', a: "Pass at build time: flutter run --dart-define=API_KEY=x, read with String.fromEnvironment('API_KEY'). In CI, inject from secrets. Never hardcode or commit .env files." },
    { id: 'fps_5', q: 'What identifiers become permanent after first release?', a: 'Android applicationId and iOS bundle ID — changing them creates a NEW app on the stores, orphaning installs, reviews, and ratings. Choose carefully before v1.0.' },
  ],
  'widgets-intro': [
    { id: 'wi_1', q: 'Name the three trees and their roles.', a: 'Widget tree: immutable configurations, rebuilt constantly (cheap). Element tree: persistent instances that diff widgets and hold state. RenderObject tree: layout and painting (expensive, aggressively reused).' },
    { id: 'wi_2', q: 'Why are widget rebuilds cheap?', a: 'Widgets are just lightweight config objects. The diff (by runtimeType + key) lets elements and render objects — the expensive parts — survive and update in place. Only genuinely changed parts do real work.' },
    { id: 'wi_3', q: "What is BuildContext really?", a: "A handle to a widget's position in the element tree. Theme.of(context) and similar walk UP the tree from that position — which is why a context above a Provider can't find it." },
    { id: 'wi_4', q: 'Widget classes vs helper methods returning widgets?', a: "Classes: get their own element, can be const, diff independently — parent rebuilds can skip them. Helper methods: inlined into the parent's build, always re-executed. Extract classes, not methods." },
    { id: 'wi_5', q: 'SizedBox vs Container for spacing?', a: 'SizedBox is the lightweight dedicated tool for fixed dimensions/gaps (and has const). Container bundles decoration/padding/constraints machinery you\'re not using — heavier for plain spacing.' },
  ],
  'stateless-stateful-widgets': [
    { id: 'ssw_1', q: 'Walk through the StatefulWidget lifecycle.', a: 'createState → initState (once: init controllers/subscriptions) → didChangeDependencies (after initState + when inherited deps change) → build (many times) → didUpdateWidget (parent passed new config) → dispose (cleanup).' },
    { id: 'ssw_2', q: 'Why does State survive when widgets rebuild?', a: 'State lives in the ELEMENT tree, not the widget tree. As long as the diff matches the new widget to the same element (same runtimeType + key), the element — and its State — persist.' },
    { id: 'ssw_3', q: 'What exactly does setState do?', a: "Runs your mutation callback, marks this State's element dirty, and schedules a rebuild of THIS subtree only on the next frame. It does not rebuild the whole app." },
    { id: 'ssw_4', q: 'What must never happen inside build()?', a: 'Side effects: network calls, setState, creating controllers, heavy computation. build runs often and must be a fast, pure function of current state. Init work goes in initState; async data via FutureBuilder or state management.' },
    { id: 'ssw_5', q: 'When do you choose Stateful over Stateless?', a: 'Only when the widget OWNS data that changes over time (local UI state: toggles, text input, animations). Pure rendering of inputs → Stateless. Shared app data → state management, not setState.' },
  ],
  'material-cupertino': [
    { id: 'mc_1', q: 'What does ColorScheme.fromSeed do?', a: 'Material 3 generates a complete, harmonious color palette (primary, secondary, surfaces, containers, error — light and dark) from ONE seed color. Whole-app theming from a single brand color.' },
    { id: 'mc_2', q: 'How do you support dark mode cleanly?', a: 'Define theme: and darkTheme: on MaterialApp with themeMode: ThemeMode.system, and consume ONLY via Theme.of(context).colorScheme — never hardcode colors. Dark mode then just works.' },
    { id: 'mc_3', q: 'What is the adaptive widget pattern?', a: 'Constructors like Switch.adaptive() render Material style on Android and Cupertino style on iOS automatically. Page transitions adapt too. Platform-appropriate feel without duplicating UI trees.' },
    { id: 'mc_4', q: 'When would you build full per-platform UIs (Material AND Cupertino)?', a: 'Rarely — when native feel is a core product requirement worth nearly doubling UI code. Most production apps use Material 3 everywhere plus adaptive touches where users notice (switches, transitions).' },
    { id: 'mc_5', q: 'Why does MaterialApp matter beyond theming?', a: 'It wires navigation (Navigator), localization delegates, Directionality, MediaQuery, and Material behaviors (overlays, snackbars). Many .of(context) lookups depend on it being at the root.' },
  ],
  'styling-theming': [
    { id: 'st_1', q: "Why can't Container have both color: and decoration:?", a: 'They conflict — color is shorthand for a BoxDecoration color. Providing both throws an assertion. Put the color INSIDE the decoration when using one.' },
    { id: 'st_2', q: 'How do you style every button in the app at once?', a: 'Component themes in ThemeData: elevatedButtonTheme: ElevatedButtonThemeData(style: ...). Every ElevatedButton inherits it; restyle the app by editing one place.' },
    { id: 'st_3', q: 'What is WidgetStateProperty?', a: 'A value that varies by interactive state (pressed/hovered/focused/disabled): WidgetStateProperty.resolveWith((states) => states.contains(WidgetState.pressed) ? darker : normal). Used throughout Material component styling.' },
    { id: 'st_4', q: 'What is ThemeExtension for?', a: 'Adding CUSTOM design tokens (success color, brand gradient) to ThemeData with proper light/dark variants and animation lerping — the professional home for non-Material tokens. Access: Theme.of(context).extension<MyTokens>().' },
    { id: 'st_5', q: 'Why respect textScaler?', a: 'Users increase system font size for accessibility. Fixed-height containers with fixed-size text break at 1.5x scale. Test at large text scales; let text size flow from the theme and layout flex.' },
  ],
  'assets-fonts-images': [
    { id: 'afi_1', q: 'How does resolution-aware asset loading work?', a: "Provide assets/img.png plus assets/2.0x/img.png and 3.0x/ variants — Flutter automatically picks the best match for the device's pixel ratio. Crisp images on every screen density." },
    { id: 'afi_2', q: 'Why cached_network_image over Image.network?', a: 'Image.network caches in memory only (gone on restart). cached_network_image adds disk caching, placeholders, fade-in, and error widgets — production behavior in one widget.' },
    { id: 'afi_3', q: 'What happens if you use an undeclared asset?', a: 'Runtime crash: "Unable to load asset" — assets are bundled only if declared in pubspec.yaml under flutter: assets:. It compiles fine; it fails when the screen loads. Folder paths need a trailing /.' },
    { id: 'afi_4', q: 'How do you reduce Flutter app download size?', a: 'Compress images (WebP ~30-70% smaller than PNG), drop unused font weights, use AAB (per-device splits), and audit with flutter build appbundle --analyze-size — fonts and images dominate bloated apps.' },
    { id: 'afi_5', q: 'How do you load a bundled JSON/config file?', a: "final raw = await rootBundle.loadString('assets/config.json'); final data = jsonDecode(raw); — rootBundle accesses anything declared in pubspec assets." },
  ],
  'responsive-widgets': [
    { id: 'rw_1', q: "Recite Flutter's one-sentence layout model.", a: '"Constraints go DOWN, sizes go UP, parent sets position." Parents tell children their min/max bounds; children choose a size within them; parents place them. Every layout behavior follows from this.' },
    { id: 'rw_2', q: 'Expanded vs Flexible?', a: 'Both share remaining flex space. Expanded FORCES the child to fill its share (tight). Flexible ALLOWS the child to be smaller (loose). Expanded is Flexible with fit: FlexFit.tight.' },
    { id: 'rw_3', q: 'MediaQuery vs LayoutBuilder?', a: "MediaQuery.sizeOf: the whole screen — good for app-level breakpoints. LayoutBuilder: the constraints of THIS widget's slot — the right tool for components that adapt to the space they actually got." },
    { id: 'rw_4', q: 'Why does ListView inside Column crash?', a: 'Column gives children unbounded height; ListView wants to fill available height = infinity → "unbounded height" error. Fix: wrap the ListView in Expanded (bounds it to remaining space).' },
    { id: 'rw_5', q: 'Responsive vs adaptive design?', a: 'Responsive: the same layout flexes to fit (flex, wrapping). Adaptive: STRUCTURE changes per form factor — list on phone, list+detail side-by-side on tablet, NavigationBar → NavigationRail.' },
  ],
  'git-for-flutter': [
    { id: 'gff_1', q: 'What must NEVER be committed in a Flutter repo?', a: 'Keystores (*.jks), key.properties, .env files, and store API keys. Build artifacts (/build, .dart_tool) belong in .gitignore. A keystore in a public repo means anyone can sign as you.' },
    { id: 'gff_2', q: 'What happens if you lose your Android release keystore?', a: 'Without Play App Signing enrollment: you can NEVER update your published app — permanent lockout from your own listing. Enroll in Play App Signing and vault the upload keystore in a password manager.' },
    { id: 'gff_3', q: 'How do you inject API keys at build time?', a: "flutter build --dart-define=API_KEY=value; read via const String.fromEnvironment('API_KEY'). CI injects from repo secrets. The key never enters Git history." },
    { id: 'gff_4', q: 'Should generated files (*.g.dart, *.freezed.dart) be committed?', a: 'Team choice: committing means checkouts build without running codegen; ignoring keeps diffs clean but requires build_runner before first build. Pick one policy and document it.' },
    { id: 'gff_5', q: 'Why tag releases in Git?', a: 'git tag v1.2.0 marks the exact commit shipped to stores — incident response can check out precisely what users are running, and CI can trigger release builds from tags.' },
  ],
  'layouts-constraints': [
    { id: 'lc_1', q: "Why does Container sometimes ignore its width?", a: "Tight constraints from the parent (min == max) override the child's preference — a Container directly in Scaffold's body gets tight screen-size constraints. Loosen with Center/Align around it." },
    { id: 'lc_2', q: 'What are tight, loose, and unbounded constraints?', a: 'Tight: min == max (forced size). Loose: min 0, bounded max (child chooses up to max). Unbounded: max = infinity (inside scrollables on the scroll axis) — children wanting "all space" crash here.' },
    { id: 'lc_3', q: 'Why does TextField inside Row throw?', a: 'Row gives unbounded width on the main axis; TextField wants to fill available width = infinity → "BoxConstraints forces an infinite width". Wrap it in Expanded to bound it.' },
    { id: 'lc_4', q: 'How does Expanded actually work inside Row/Column?', a: 'The flex layout sizes non-flex children first, then divides REMAINING space among flex children by their flex factors, imposing tight constraints from each share.' },
    { id: 'lc_5', q: 'Why use IntrinsicHeight sparingly?', a: 'It performs a speculative extra layout pass to ask children their natural size — O(n²) in nesting. Fine occasionally; a performance trap in lists or deep trees.' },
  ],
  'scrollable-widgets': [
    { id: 'sw_1', q: 'How does ListView.builder achieve constant memory on 1M items?', a: 'It builds only visible items plus a small cacheExtent window; elements/render objects are recycled as items scroll out. Cost scales with screen size, not list length.' },
    { id: 'sw_2', q: 'Why is shrinkWrap: true a performance concern?', a: 'It forces measuring ALL children up front to size the list — O(n) layout, defeating laziness. Usually a band-aid for unbounded-height errors that Expanded solves properly.' },
    { id: 'sw_3', q: 'Why add keys to stateful list items?', a: 'Without keys, the diff matches elements by position — removing item 0 shifts every element\'s identity, attaching state (checkboxes, animations) to the WRONG items. ValueKey(item.id) makes state follow data.' },
    { id: 'sw_4', q: 'What are slivers?', a: 'Composable scroll-effect pieces inside CustomScrollView: SliverAppBar (collapsing/pinned headers), SliverList, SliverGrid — mixed content and fancy effects in ONE scrolling viewport.' },
    { id: 'sw_5', q: 'How do you implement infinite scroll?', a: 'Listen to a ScrollController; when position.pixels nears maxScrollExtent (e.g., within 300px), fetch the next page — guarded against duplicate in-flight fetches. Append results, let builder handle the rest.' },
  ],
  'forms-input': [
    { id: 'fin_1', q: 'How does Form validation work?', a: 'Form holds a GlobalKey<FormState>; each TextFormField has a validator returning null (valid) or an error string (shown inline). formKey.currentState!.validate() runs all validators and returns overall validity.' },
    { id: 'fin_2', q: 'Why create TextEditingControllers in initState, not build?', a: 'build runs on every rebuild — recreating the controller wipes text and cursor position constantly. Create once in initState, dispose in dispose.' },
    { id: 'fin_3', q: 'What does autovalidateMode.onUserInteraction do?', a: 'Shows validation errors live as the user types — but only after they\'ve first interacted with the field. Errors appear when helpful, not before the user has done anything.' },
    { id: 'fin_4', q: 'How do you show a backend error (email already in use) on the right field?', a: 'Map the typed exception to field-level state (e.g., store emailServerError), surface it via the field\'s validator or InputDecoration errorText, and clear it when the user edits the field.' },
    { id: 'fin_5', q: 'Why disable the submit button while submitting?', a: 'Prevents double-submission (duplicate requests/orders) and gives clear feedback. Pattern: bool submitting in state; onPressed: submitting ? null : submit; show a spinner in the button.' },
  ],
  'navigation-routing': [
    { id: 'nr_1', q: 'push vs pushReplacement vs pushAndRemoveUntil?', a: 'push: adds a screen (back returns). pushReplacement: swaps the top (back skips it — use after login). pushAndRemoveUntil(..., (r) => false): clears the entire stack — use for logout.' },
    { id: 'nr_2', q: 'How do you get a result back from a pushed screen?', a: 'The pusher awaits: final result = await Navigator.push<Note>(...). The pushed screen returns it: Navigator.pop(context, note). Check context.mounted after the await before using context.' },
    { id: 'nr_3', q: 'Why go_router over raw Navigator for real apps?', a: "Declarative paths, auth redirect guards (redirect:), deep links and web URLs, typed path params, nested navigation — it wraps Navigator 2.0's power without its notorious API complexity." },
    { id: 'nr_4', q: 'How do auth-guarded routes work in go_router?', a: "The redirect callback inspects auth state per navigation: unauthenticated + not going to /login → return '/login'; authenticated + at /login → return '/home'; else null (no redirect). Auth logic centralized in the router." },
    { id: 'nr_5', q: 'Why is pushing login on logout a bug?', a: 'The authenticated stack remains underneath — back button returns into the app while logged out. Logout must CLEAR the stack: pushAndRemoveUntil or state-driven root swapping.' },
  ],
  'dialogs-loading': [
    { id: 'dl_1', q: 'How do you return a confirmation from a dialog?', a: 'showDialog<bool> returns Future<bool?>; buttons pop with values: Navigator.pop(ctx, true/false). Await it, treating null (dismissed) as "not confirmed": final ok = await showConfirmDialog(...) ?? false.' },
    { id: 'dl_2', q: 'Why ScaffoldMessenger instead of Scaffold.of for snackbars?', a: 'ScaffoldMessenger is scoped above individual Scaffolds — snackbars survive navigation pops and work without a direct Scaffold ancestor. Scaffold.of broke in both cases (pre-2.0 pattern).' },
    { id: 'dl_3', q: "What's the robust loading-state pattern?", a: "Render loading FROM state (bloc's isLoading), don't imperatively push spinner dialogs. State-driven overlays can't get \"stuck\" — the failure path emits a state and the overlay disappears with it." },
    { id: 'dl_4', q: 'Why check context.mounted after await before showing a dialog?', a: "The user may have navigated away during the await — the context's element is defunct, and using it throws. if (!context.mounted) return; is mandatory hygiene (and linted)." },
    { id: 'dl_5', q: 'Where do shared dialog helpers belong?', a: 'core/ as functions: showErrorDialog(context, message), showConfirmDialog(...) — one consistent UX, one place to restyle, used by every feature.' },
  ],
  'inherited-widgets': [
    { id: 'iw_1', q: 'How does Theme.of(context) find the theme?', a: "It calls context.dependOnInheritedWidgetOfExactType<Theme-related InheritedWidget>() — walking UP the element tree from the calling context, returning the nearest ancestor's data and subscribing to its changes." },
    { id: 'iw_2', q: 'What does updateShouldNotify control?', a: 'When the InheritedWidget is rebuilt with new data, updateShouldNotify(old) decides whether dependent widgets rebuild. Return old.data != data to notify only on real changes.' },
    { id: 'iw_3', q: 'How does Provider relate to InheritedWidget?', a: 'Provider IS an InheritedWidget plus lifecycle management. watch/of(listen:true) calls dependOnInheritedWidgetOfExactType (subscribes); read uses a non-subscribing lookup; notifyListeners triggers the inherited rebuild.' },
    { id: 'iw_4', q: 'Why does "could not find Provider" happen?', a: "The lookup walks UP from the calling context — if the Provider is below it, or in a different route subtree, it's invisible. Provide above the consumers (commonly above MaterialApp for app-wide state)." },
    { id: 'iw_5', q: 'Subscribe vs read-once on inherited data?', a: 'dependOn... subscribes (rebuild on change) — right in build. getInheritedWidgetOfExactType reads WITHOUT subscribing — right in callbacks where rebuilding makes no sense (context.read is this).' },
  ],
  'packages-pubdev': [
    { id: 'pp_1', q: 'How do you evaluate a pub.dev package for production?', a: 'Maintenance signals first: recent commits/publishes, issue responsiveness. Then pub points (static quality), likes/downloads, verified publisher or Flutter Favorite badge, platform support, and dependency weight.' },
    { id: 'pp_2', q: 'What does ^1.2.0 mean?', a: "Caret syntax: >=1.2.0 <2.0.0 — any compatible version below the next MAJOR (semver: majors may break, minors/patches shouldn't). The recommended default constraint." },
    { id: 'pp_3', q: 'How do you resolve a version conflict between packages?', a: 'Try flutter pub upgrade to find a compatible set; check for newer majors of the conflicting packages; as a TEMPORARY patch, dependency_overrides forces a version — remove it as soon as upstream fixes land.' },
    { id: 'pp_4', q: "Why wrap third-party packages behind your own interfaces?", a: 'Swapping http→dio (or analytics vendors) then touches one adapter file instead of forty screens. Every external dependency is a liability across Flutter upgrades — abstraction keeps them replaceable.' },
    { id: 'pp_5', q: 'dependencies vs dev_dependencies?', a: 'dependencies ship in the app (http, bloc). dev_dependencies exist only for development — tests, lints, build_runner codegen — and are excluded from release builds.' },
  ],
  'design-principles': [
    { id: 'dp_1', q: 'Apply single responsibility to a Flutter screen.', a: 'The widget renders. A bloc/controller holds the logic. A repository fetches data. A service wraps external APIs. When the screen file contains Firestore queries, responsibilities have collapsed — and testing is impossible.' },
    { id: 'dp_2', q: 'What is the repository pattern and what does it buy?', a: 'An abstract interface (NotesRepository) hiding the data source behind domain-typed methods. Buys: swappable backends (SQLite→Firestore without touching UI), unit-testable logic (inject fakes), and one place for data concerns.' },
    { id: 'dp_3', q: 'How does dependency injection improve testability?', a: 'Classes receive dependencies via constructor instead of creating them — tests pass mocks/fakes. NotesBloc(repo) tests with FakeRepo in milliseconds; NotesBloc() that news up Firestore inside can only be tested against Firebase.' },
    { id: 'dp_4', q: 'What is dependency inversion in Flutter terms?', a: 'Depend on abstractions, not concretions: the bloc takes a NotesRepository interface, never FirebaseFirestore directly. High-level logic stays ignorant of low-level details — which become swappable configuration.' },
    { id: 'dp_5', q: 'When is full clean architecture overkill?', a: 'Solo MVPs and small apps: use-case classes and triple-layer ceremony per feature slow you down without payoff. The 80/20: repository interfaces + constructor injection + logic out of widgets.' },
  ],
  'state-management-intro': [
    { id: 'smi_1', q: 'Ephemeral vs app state?', a: 'Ephemeral: single-widget UI state (toggle, text input, animation) — setState is correct. App state: shared, long-lived data (auth, cart, notes) — needs a home above the widgets with change notification.' },
    { id: 'smi_2', q: 'What is "lifting state up" and its limit?', a: 'Moving state to the lowest common ancestor of widgets needing it, passing data down and callbacks up. Stops scaling when drilling through many layers or when distant screens need the same data.' },
    { id: 'smi_3', q: 'What three questions does every state solution answer?', a: 'Where does state live (above its consumers)? How do widgets read it (InheritedWidget-based lookup)? How do they learn of changes (Listenable/Stream subscriptions triggering targeted rebuilds)?' },
    { id: 'smi_4', q: 'What is unidirectional data flow?', a: 'Events/intentions flow UP (user tapped → event/method call); state flows DOWN (new state → UI rebuilds). No widget mutates shared state directly — making changes traceable and debuggable.' },
    { id: 'smi_5', q: 'Is setState bad?', a: "No — it's the correct tool for local UI state and the foundation everything else builds on. The smell is setState managing SHARED data through prop-drilling and callback chains." },
  ],
  'provider-changenotifier': [
    { id: 'pcn_1', q: 'watch vs read vs select?', a: 'watch: subscribes, rebuilds on change — build methods only. read: one-shot access, no subscription — callbacks. select: subscribes to a SLICE ((m) => m.count) — rebuilds only when that slice changes.' },
    { id: 'pcn_2', q: 'How does ChangeNotifier deliver updates?', a: 'It maintains a listener list; notifyListeners() invokes them. Provider bridges this to the element tree: subscribed widgets (watch/Consumer) are marked dirty and rebuild next frame.' },
    { id: 'pcn_3', q: 'Why does context.watch in onPressed throw?', a: "Subscriptions are registered during build — a callback runs outside build, so there's nothing to subscribe. Use context.read in callbacks; watch belongs in build only." },
    { id: 'pcn_4', q: 'How do you prevent over-rebuilding with Provider?', a: "select for slices instead of watching whole models, Consumer wrapping only the dynamic part with the static subtree passed via child:, and splitting god-models into focused per-domain notifiers." },
    { id: 'pcn_5', q: 'When is plain ValueNotifier enough?', a: 'Small shared values (theme mode, a counter, a flag): ValueNotifier + ValueListenableBuilder is built-in, zero dependencies, perfectly adequate. Not every app needs a state library.' },
  ],
  'riverpod': [
    { id: 'rp_1', q: 'What does Riverpod fix about Provider?', a: 'Providers live OUTSIDE the widget tree as compile-checked globals — no "not found above context" runtime errors, no tree-scoping bugs, easy composition (providers watching providers), auto-dispose, and test overrides.' },
    { id: 'rp_2', q: 'What is AsyncValue and why does it matter?', a: 'A union of loading/data/error that every async provider returns. .when(loading:, data:, error:) FORCES handling all three — forgotten-spinner and unhandled-error bugs become unrepresentable.' },
    { id: 'rp_3', q: 'How do provider overrides enable testing?', a: 'ProviderContainer(overrides: [repoProvider.overrideWithValue(FakeRepo())]) swaps any dependency for the whole graph — business logic tested with zero widgets and zero mocking ceremony.' },
    { id: 'rp_4', q: 'What does autoDispose do and when do you NOT want it?', a: "Tears down provider state when nothing watches it (fresh data per screen visit). Don't use for app-wide state (auth/session) — it would reset on navigation when temporarily unwatched." },
    { id: 'rp_5', q: 'ref.watch vs ref.read vs ref.listen?', a: 'watch: subscribe and rebuild/recompute (build methods and provider bodies). read: one-shot (callbacks). listen: run side effects on changes (show snackbar, navigate) without rebuilding.' },
  ],
  'bloc-basics': [
    { id: 'bb_1', q: "Walk through BLoC's data flow.", a: 'UI dispatches an EVENT (LoginRequested) → bloc\'s registered handler runs business logic (calls services) → handler EMITS states (Loading → Success/Failure) → UI rebuilds from each state. Strictly one-directional.' },
    { id: 'bb_2', q: 'Cubit vs Bloc?', a: 'Cubit: direct methods calling emit() — less ceremony, great for simple features. Bloc: explicit event objects with on<Event> handlers — full traceability (every change has a named cause) and event transformers (debounce, restartable).' },
    { id: 'bb_3', q: 'Why must states be immutable with value equality?', a: 'Bloc skips emitting a state equal to the current one, and rebuild triggers compare states. Mutating the current state means old == new — no emission, frozen UI. Equatable/freezed + copies fix it.' },
    { id: 'bb_4', q: 'BlocBuilder vs BlocListener vs BlocConsumer?', a: 'Builder: returns UI from state (runs many times). Listener: side effects — dialogs, navigation, snackbars (fires once per state CHANGE). Consumer: both in one widget. Side effects in builder is the classic bug.' },
    { id: 'bb_5', q: 'What do event transformers control?', a: 'Concurrency of event handling: droppable ignores events while busy, restartable cancels the previous handler (search-as-you-type), sequential queues. From the bloc_concurrency package.' },
  ],
  'bloc-advanced': [
    { id: 'ba_1', q: 'How does state-driven routing work with auth?', a: 'A root BlocBuilder<AuthBloc, AuthState> returns the whole screen tree per state: LoginView, VerifyEmailView, or NotesView. Navigation is a pure function of auth state — no imperative pushes for auth flows anywhere.' },
    { id: 'ba_2', q: 'How should exceptions flow from services to UI?', a: 'Services catch platform errors and throw TYPED exceptions with user-presentable messages → blocs catch those and emit Failure states → UI renders the message with a recovery action. Raw errors never cross layer boundaries.' },
    { id: 'ba_3', q: 'How do two blocs share data without coupling?', a: "Never reference each other. Either both consume a shared repository's stream, or a parent widget listens to bloc A (BlocListener) and adds events to bloc B. Repos are the meeting point." },
    { id: 'ba_4', q: 'What is BlocObserver?', a: 'A global hook receiving every event, transition, and error from ALL blocs — one class giving you an app-wide audit log. Production debugging gold: the session log tells the story of what happened.' },
    { id: 'ba_5', q: 'Why can emit after await crash?', a: 'The handler may have been cancelled (bloc closed, restartable transformer superseded it). Guard long handlers: check emit.isDone / isClosed before emitting after awaits.' },
  ],
  'getx-redux-overview': [
    { id: 'gr_1', q: 'Give a fair assessment of GetX.', a: 'Optimizes typing speed: reactive .obs, context-free routing/snackbars, built-in DI. Costs: hides Flutter fundamentals, global registry hurts test isolation, encourages god-controllers. Fine for prototypes and small scopes; risky for large team products.' },
    { id: 'gr_2', q: 'What is the Redux pattern?', a: 'One immutable store; UI dispatches actions; pure reducers compute (state, action) → newState; widgets subscribe via StoreConnector. Predictable and time-travel debuggable, but verbose — uncommon in new Flutter.' },
    { id: 'gr_3', q: 'Why is mixing state libraries in one app a problem?', a: 'Two sources of truth, two mental models, double the onboarding, and bridging glue between them. Pick one app-state solution; consistency beats theoretical per-feature optimality.' },
    { id: 'gr_4', q: 'What is Obx in GetX?', a: 'A widget that auto-tracks any .obs observables read inside its closure and rebuilds when they change — GetX\'s reactive primitive: Obx(() => Text(controller.count.toString())).' },
    { id: 'gr_5', q: 'Which state solutions dominate serious new Flutter projects?', a: 'Riverpod (compile-safe, async-first, concise) and BLoC (structured, traceable, team-uniform). Provider remains widespread in existing codebases; GetX is common in agency/tutorial ecosystems.' },
  ],
  'reactive-rxdart': [
    { id: 'rx_1', q: 'What does BehaviorSubject add over a broadcast StreamController?', a: 'It REPLAYS the latest value to every new subscriber — late subscribers immediately get current state instead of waiting for the next emission. The standard holder for auth state and cached lists.' },
    { id: 'rx_2', q: 'Design search-as-you-type that never shows stale results.', a: 'input.debounceTime(300ms) (wait for typing pause) .distinct() (skip identical queries) .switchMap(api.search) (cancel the previous in-flight search when a new query arrives). Four operators, zero race conditions.' },
    { id: 'rx_3', q: 'switchMap vs flatMap?', a: 'Both map events to inner streams. switchMap CANCELS the previous inner stream when a new event arrives (perfect for searches). flatMap runs all concurrently — stale results can arrive out of order.' },
    { id: 'rx_4', q: 'What does combineLatest do?', a: 'Combines multiple streams: emits whenever ANY source emits, using the latest value from each. UI example: visibleNotes = combineLatest(notes$, filter$, apply) — recomputed when either data or filter changes.' },
    { id: 'rx_5', q: "What's the cost of forgetting to close Subjects?", a: 'Memory leaks plus "Stream already closed"/ghost-listener bugs elsewhere. Every StreamController/Subject you create, you close — in dispose() or the service\'s teardown.' },
  ],
  'choosing-state-management': [
    { id: 'csm_1', q: 'Which state solution for a 3-person startup MVP?', a: 'Riverpod: compile-time safety, AsyncValue forcing async handling, minimal boilerplate, great testing. BLoC if the team already knows it or expects to scale headcount fast (uniformity wins at scale).' },
    { id: 'csm_2', q: 'What do ALL Flutter state solutions share?', a: 'Three primitives: state lives above its consumers, widgets look it up via InheritedWidget mechanics, and a notification channel (Listenable/Stream) triggers targeted rebuilds. They differ in safety, ceremony, and traceability.' },
    { id: 'csm_3', q: 'How do you keep a codebase migratable between state solutions?', a: "Keep logic OUT of state classes: repositories and services as plain Dart with interfaces; the state layer stays a thin notification wrapper. Then swapping libraries touches the thin layer, not the logic." },
    { id: 'csm_4', q: "When does BLoC's ceremony pay for itself?", a: 'Large teams (uniform structure across 20 devs), audit-heavy domains (every change traces to a named event — BlocObserver logs it), and complex event semantics (transformers for debounce/restartable).' },
    { id: 'csm_5', q: 'How should you answer "which is best" in an interview?', a: 'With a decision tree, not a favorite: classify the state, weigh team size and async intensity, name trade-offs (Provider simplicity / Riverpod safety / BLoC traceability), and note that repositories keep the choice reversible.' },
  ],
  'http-rest-flutter': [
    { id: 'hr_1', q: 'Why does the http package "ignore" server errors?', a: 'It does NOT throw on non-2xx responses — a 500 returns normally and you\'ll parse an error page as JSON. Always check res.statusCode explicitly. (dio throws DioException by default.)' },
    { id: 'hr_2', q: 'What do dio interceptors enable?', a: 'Cross-cutting concerns in one place: inject auth headers on every request, log traffic, and implement 401 → refresh token → replay the failed request. Without them, that logic duplicates per call site.' },
    { id: 'hr_3', q: 'Design the 401-refresh-retry flow.', a: 'Error interceptor: on 401 (and not the refresh endpoint itself) → trigger ONE token refresh (queue concurrent 401s behind it) → replay queued requests with the new token → if refresh fails, force logout.' },
    { id: 'hr_4', q: 'Which requests are safe to auto-retry?', a: 'Idempotent ones: GET, PUT, DELETE — same result if repeated. Never blindly retry POSTs (duplicate orders/payments). Retry transient failures (timeouts, 5xx) with exponential backoff; never retry 4xx.' },
    { id: 'hr_5', q: 'Why set timeouts explicitly?', a: 'Default timeouts are effectively infinite — a dead network means spinners forever. Set connectTimeout (~10s) and receiveTimeout (~15s); map timeout exceptions to a retryable error UI.' },
  ],
  'json-serialization': [
    { id: 'js_1', q: "Why can json['price'] as double crash in production?", a: "JSON 5 parses as int, not double — the cast throws. Servers send whichever. Safe pattern: (json['price'] as num).toDouble() handles both." },
    { id: 'js_2', q: 'What does freezed generate?', a: 'From one annotated class: copyWith, ==/hashCode, toString, optional fromJson/toJson (with json_serializable), and union types — every data-class need from a single definition.' },
    { id: 'js_3', q: 'How do you survive unknown enum values from the server?', a: 'Always map with a fallback: Status.values.asNameMap()[raw] ?? Status.unknown (or @JsonKey(unknownEnumValue:)). New server values then degrade gracefully in old app versions instead of crashing the parse.' },
    { id: 'js_4', q: 'When should JSON parsing move off the UI thread?', a: 'Payloads big enough to exceed a frame budget (~roughly >100KB): await compute(parseFn, body) parses in an isolate, keeping scroll and animations smooth during the decode.' },
    { id: 'js_5', q: 'What are DTOs vs domain models?', a: 'DTOs mirror the exact API shape (generated); domain models are what the app needs; mappers convert. API renames then touch one mapper, not forty screens. Worth it when you don\'t control the API.' },
  ],
  'websockets-graphql-flutter': [
    { id: 'wg_1', q: 'When do WebSockets beat REST polling?', a: 'Whenever the SERVER knows first: chat, live scores, presence, collaborative editing. Polling burns battery and lags by the poll interval; a socket pushes instantly over one persistent connection.' },
    { id: 'wg_2', q: 'What does production WebSocket handling require?', a: 'Reconnection with exponential backoff (mobile networks churn), heartbeat ping/pong to detect dead connections, resubscribing to topics after reconnect, and a typed message protocol (JSON envelopes).' },
    { id: 'wg_3', q: 'What problem does GraphQL solve for mobile specifically?', a: "Over-fetching: mobile asks for exactly the fields its screens need (less cellular data, faster parses) and batches related resources in one query instead of N REST round-trips." },
    { id: 'wg_4', q: 'How do GraphQL subscriptions work?', a: "A subscription operation runs over a WebSocket transport — the server pushes a new result every time the watched data changes. The GraphQL flavor of realtime, used via graphql_flutter's Subscription." },
    { id: 'wg_5', q: 'How does a WebSocket appear in Flutter code?', a: 'As a Stream + sink: WebSocketChannel.connect(uri) gives channel.stream to listen and channel.sink.add to send — so StreamBuilder renders live socket data directly.' },
  ],
  'local-storage-sqlite': [
    { id: 'ls_1', q: 'Where do you store an auth token and why?', a: 'flutter_secure_storage — Keychain (iOS) / Keystore-encrypted prefs (Android). SharedPreferences is plaintext on disk, readable on rooted devices. Prefs are for non-sensitive settings only.' },
    { id: 'ls_2', q: 'How do you handle SQLite schema changes for shipped apps?', a: 'Bump the version in openDatabase and write onUpgrade migrations: if (oldVersion < 2) ALTER TABLE... Every shipped schema version needs a path forward, or existing users crash on update.' },
    { id: 'ls_3', q: 'Why parameterized queries (whereArgs) always?', a: "String-built SQL with user input = SQL injection and quoting bugs. where: 'owner = ?', whereArgs: [id] lets SQLite handle escaping — correctness AND security." },
    { id: 'ls_4', q: 'What does drift add over raw sqflite?', a: 'Type-safe, compile-checked queries (typos become compile errors) and reactive .watch() queries returning Streams — query results that auto-update the UI when underlying data changes.' },
    { id: 'ls_5', q: 'Sketch offline-first architecture.', a: 'Local DB is the single source of truth — UI renders DB streams. Network sync writes INTO the DB in the background; pending local writes queue with retry. The UI never waits on the network.' },
  ],
  'firebase-setup': [
    { id: 'fs_1', q: 'What does flutterfire configure do?', a: 'Authenticates with your Firebase project, registers iOS/Android (and web) apps with correct IDs, downloads platform configs, and generates firebase_options.dart for Firebase.initializeApp — eliminating manual setup errors.' },
    { id: 'fs_2', q: 'Why separate dev and prod Firebase projects?', a: 'Developing against prod risks polluting real user data, skewing analytics, and accidental destructive writes. myapp-dev / myapp-prod with per-flavor configs costs minutes and prevents disasters.' },
    { id: 'fs_3', q: 'What must happen before any Firebase call?', a: 'WidgetsFlutterBinding.ensureInitialized() then await Firebase.initializeApp(options: DefaultFirebaseOptions.currentPlatform) — both in main() before runApp. Skipping it crashes at the first Firebase touch.' },
    { id: 'fs_4', q: "What are Firebase's main trade-offs vs a custom backend?", a: 'Wins: speed to market, managed scaling, integrated auth/db/storage/push. Costs: vendor lock-in (Firestore model and rules don\'t port), opaque pricing at scale, limited query power. Great for MVPs; evaluate at scale.' },
    { id: 'fs_5', q: 'Which Firebase plan do you need?', a: 'Spark (free) covers auth, Firestore, storage, messaging with generous quotas — the entire learning path. Blaze (pay-as-you-go) is required for Cloud Functions and beyond-quota usage.' },
  ],
  'firebase-auth-flow': [
    { id: 'fa_1', q: 'What is authStateChanges and why is it central?', a: 'A Stream<User?> emitting on every auth change (login, logout, expiry). The root widget listens and switches screen trees — making navigation react automatically to auth from anywhere in the app.' },
    { id: 'fa_2', q: 'How do you enforce verified email before app access?', a: 'After register: sendEmailVerification, route to a verify screen. To check: await user.reload() THEN read emailVerified (it\'s cached otherwise). Gate the main UI on the refreshed flag.' },
    { id: 'fa_3', q: 'Why map FirebaseAuthException codes?', a: 'Raw messages are technical and inconsistent. A switch over e.code (user-not-found, wrong-password, email-already-in-use...) produces friendly, field-targeted text — and avoids leaking which field was wrong on login.' },
    { id: 'fa_4', q: 'When is Sign in with Apple mandatory?', a: 'App Store rule: if you offer ANY third-party social login (Google, Facebook), you MUST also offer Sign in with Apple. Shipping Google-only to iOS is an automatic rejection.' },
    { id: 'fa_5', q: 'A user signs in with Google using an email that has a password account — what happens?', a: "account-exists-with-different-credential: Firebase blocks the second method by default. Handle by signing into the original method then linkWithCredential to merge — preserving the user's data under one account." },
  ],
  'cloud-firestore': [
    { id: 'cf_1', q: 'How do Firestore realtime listeners differ from polling?', a: 'snapshots() opens a persistent push channel: the server sends changes the moment they commit — including changes from other devices. Plus latency compensation (local writes appear instantly) and offline caching built in.' },
    { id: 'cf_2', q: 'Write rules so users only access their own notes.', a: 'match /notes/{id} { allow read, update, delete: if request.auth != null && request.auth.uid == resource.data.ownerId; allow create: if request.auth.uid == request.resource.data.ownerId; } — authorization lives in rules, not app code.' },
    { id: 'cf_3', q: 'Why are default test-mode rules dangerous?', a: 'allow read, write: if true means ANYONE can read and modify ALL data via the public API — no app required. Shipping them is a breach waiting to happen; write real rules with the schema.' },
    { id: 'cf_4', q: 'How does Firestore pricing shape query design?', a: 'Billed per document read/write — a 1000-doc query costs 1000 reads, and every listener re-reads changed docs. Design narrow: where + orderBy + limit, paginate with cursors, aggregate counters server-side.' },
    { id: 'cf_5', q: 'What is latency compensation?', a: 'Your local writes apply to the local cache and UI INSTANTLY, then sync to the server in the background — snappy UX on slow networks, reconciled automatically when the server confirms.' },
  ],
  'firebase-services': [
    { id: 'fsv_1', q: 'How does FCM message handling differ by app state?', a: 'Foreground: onMessage fires — YOU render a local notification. Background: system shows it; tap → onMessageOpenedApp. Terminated: tap → getInitialMessage on launch. All three need handling for complete UX.' },
    { id: 'fsv_2', q: 'How does Remote Config de-risk launches?', a: 'Flag risky features (new_checkout_enabled): ship dark, enable gradually, and if production misbehaves, disable in seconds via console — an incident becomes a config flip instead of an emergency release.' },
    { id: 'fsv_3', q: 'When must logic move to Cloud Functions?', a: 'Anything trusted: payment webhooks, privileged writes (counters, moderation), secrets, and fan-out (on message created → push to participants). Clients can be decompiled and impersonated — never give them admin logic.' },
    { id: 'fsv_4', q: 'Why ask for push permission in context?', a: 'Cold permission prompts at first launch get denied massively — and iOS lets you ask ONCE. Ask after demonstrating value ("Get notified when your order ships?") for dramatically better grant rates.' },
    { id: 'fsv_5', q: "What's the Remote Config dev-time gotcha?", a: 'minimumFetchInterval defaults to ~12h of caching — your changed flag "doesn\'t work" because the client serves cache. Set a short interval in debug builds only.' },
  ],
  'service-repository-pattern': [
    { id: 'srp_1', q: 'How do you migrate from SQLite to Firestore without touching screens?', a: 'Screens depend on a NotesRepository INTERFACE. Write FirestoreNotesRepository implementing it, swap the binding at the composition root (optionally behind a Remote Config flag). The course does exactly this.' },
    { id: 'srp_2', q: 'What is a contract test?', a: 'One shared test suite run against EVERY implementation of an interface (fake, SQLite, Firestore-emulator). All green = implementations are behaviorally interchangeable = swaps are provably safe.' },
    { id: 'srp_3', q: 'What is a leaky abstraction in a repository?', a: 'Interface methods exposing backend types — returning QuerySnapshot or Database rows. Every consumer then imports Firestore anyway. Contracts must speak domain types only: Note, Stream<List<Note>>.' },
    { id: 'srp_4', q: 'Where should concrete implementations be chosen?', a: 'One composition root — main.dart or a DI container. Everything else sees interfaces. Swapping backends, faking for tests, and flagging migrations all happen in that single file.' },
    { id: 'srp_5', q: 'How do you migrate user DATA between storage backends?', a: 'On first cloud login: backfill local → cloud (dedupe by stable ID/content hash), tombstone deletes, keep a rollback flag during transition, and verify counts before celebrating.' },
  ],
  'animations-basics': [
    { id: 'ab_1', q: 'Implicit vs explicit animations?', a: 'Implicit (AnimatedContainer, AnimatedOpacity): set a new value, Flutter animates the transition — covers ~80% of needs. Explicit (AnimationController + Tween): full control — repeat, reverse, sequencing, gesture-driven.' },
    { id: 'ab_2', q: 'What does vsync do?', a: "Ties the AnimationController's ticker to the display's frame clock (via TickerProviderStateMixin) — ticks fire in sync with frames and PAUSE when the widget is offscreen, saving battery." },
    { id: 'ab_3', q: "Why is AnimatedBuilder's child parameter important?", a: 'The builder closure re-runs EVERY tick (60-120fps). Static subtree passed via child: is built once and threaded through — only the cheap wrapper rebuilds per frame.' },
    { id: 'ab_4', q: 'Which property animations are GPU-cheap vs expensive?', a: 'Transform and opacity changes can stay on the compositor — cheap. Width/height/padding changes trigger RELAYOUT every frame — expensive. Prefer Transform.translate over animating layout in hot paths.' },
    { id: 'ab_5', q: 'How do staggered animations work on one controller?', a: 'Multiple tweens with Interval curves: Tween(...).animate(CurvedAnimation(parent: ctrl, curve: Interval(0.0, 0.5))) runs in the first half, another in Interval(0.5, 1.0) — one timeline, choreographed parts.' },
  ],
  'hero-implicit-animations': [
    { id: 'hi_1', q: 'How does Hero animate between routes?', a: 'Matching Hero tags on both screens: during the transition, Flutter lifts the child into an overlay and tweens its rect from the old position/size to the new — reading as one element flying between pages.' },
    { id: 'hi_2', q: 'Why does AnimatedSwitcher need keys?', a: 'It animates when the child CHANGES — same-type children with the same key look identical to the diff, so nothing animates. Text(\'$count\', key: ValueKey(count)) makes each value a distinct child.' },
    { id: 'hi_3', q: 'What is the container transform pattern?', a: 'A card morphs into the page it opens (OpenContainer from the animations package) — the Material motion pattern for parent-child navigation, communicating "this card IS that page".' },
    { id: 'hi_4', q: 'Why do Hero tags crash in lists?', a: "Tags must be unique per screen — a constant tag on every list item collides. Tag with identity: Hero(tag: 'note-\${note.id}')." },
    { id: 'hi_5', q: "What's the right amount of custom page transitions?", a: "Minimal: platform defaults are familiar; nonstandard transitions everywhere read as broken, not premium. Spend motion budget on Hero/container transforms in your primary flow." },
  ],
  'flutter-internals': [
    { id: 'fin2_1', q: 'What happens, tree by tree, on setState?', a: 'The element is marked dirty → next frame, build() produces new widgets → elements diff them (canUpdate: same runtimeType + key?) → surviving elements update render object properties; only real changes relayout/repaint.' },
    { id: 'fin2_2', q: 'Why do keys fix reordered-list state bugs?', a: 'Without keys the diff matches children by POSITION — state sticks to slots. ValueKey(item.id) matches by identity, so elements (and their State) follow their data through reorders and removals.' },
    { id: 'fin2_3', q: "What can GlobalKey do that ValueKey can't?", a: "Locate an element from anywhere (formKey.currentState.validate()) and REPARENT a subtree to a different tree location without losing its state. ValueKey only disambiguates among siblings." },
    { id: 'fin2_4', q: 'When does an element NOT survive a rebuild?', a: 'When canUpdate fails: the new widget at its position has a different runtimeType or different key. The element unmounts (State.dispose runs) and a fresh one is inflated.' },
    { id: 'fin2_5', q: 'What does RepaintBoundary do?', a: "Inserts a compositing layer so a frequently-repainting child doesn't dirty its ancestors' paint (and vice versa). Use around hot regions (animations, video) — each boundary costs memory, so place by measurement." },
  ],
  'performance-optimization': [
    { id: 'po_1', q: 'A screen janks during scroll — your diagnosis workflow?', a: 'Reproduce in PROFILE mode on a real device → DevTools Performance timeline → find the long frame → UI thread (build/layout) or raster thread (paint/GPU)? → inspect the flame chart for the expensive widget → targeted fix → re-measure.' },
    { id: 'po_2', q: 'Why is the Opacity widget expensive?', a: 'It forces saveLayer — rendering the subtree to an offscreen buffer before compositing. For animation use FadeTransition; for static transparency use colors with alpha. Same look, no buffer.' },
    { id: 'po_3', q: "What's the one-line fix for oversized images?", a: 'cacheWidth/cacheHeight on Image: decode at DISPLAY size. A 4000px photo in a 100px tile otherwise decodes 40x the needed pixels — memory spikes and dropped frames.' },
    { id: 'po_4', q: 'Why never judge performance in debug mode?', a: "Debug runs JIT with assertions — 5-10x slower, different bottlenecks. You'll fix phantom problems and miss real ones. Profile mode on a real device is the only honest measurement." },
    { id: 'po_5', q: 'Name the standard UI-thread jank fixes.', a: 'const widgets (diff skips them), narrowed rebuild scopes (select/buildWhen/child params), ListView.builder + itemExtent, compute() for parsing, and avoiding per-frame allocations in build.' },
  ],
  'dev-tools-inspector': [
    { id: 'dt_1', q: 'Which tool answers "why is this widget this size?"', a: "Widget Inspector's Layout Explorer: select the widget (tap-to-select on device) and see its constraints, size, and flex visually — most layout mysteries solve on sight." },
    { id: 'dt_2', q: 'How do you find excessive rebuilds?', a: 'IDE "Track widget rebuilds" shows per-widget rebuild counts inline; DevTools Performance overlays rebuild stats. A leaf rebuilding 60×/s when its data changes 1×/min is your culprit.' },
    { id: 'dt_3', q: 'How do you capture uncaught async errors?', a: 'PlatformDispatcher.instance.onError = (error, stack) { report; return true; } — alongside FlutterError.onError for framework errors. Both wired to crash reporting in production.' },
    { id: 'dt_4', q: 'What is Repaint Rainbow for?', a: 'Overlays flashing colors on regions as they repaint — anything flashing constantly that shouldn\'t be repainting reveals over-painting to isolate with RepaintBoundary or restructure.' },
    { id: 'dt_5', q: 'Why dart:developer log over print?', a: 'Structured logging: named channels, levels, error/stack attachment, and DevTools filtering. print is unstructured, can drop lines under load (debugPrint throttles), and pollutes release builds.' },
  ],
  'streams-builders-ui': [
    { id: 'sb_1', q: "Why must FutureBuilder's future not be created in build()?", a: 'build runs on every rebuild — future: fetchNotes() fires a NEW request each time: spinner loops, duplicate calls. Create once in initState, store in a field, reference the field.' },
    { id: 'sb_2', q: 'Name all four async UI states to handle.', a: 'Waiting (spinner/skeleton), error (message + retry), data (content), and EMPTY (hasData but list is empty — needs its own friendly state, not a blank screen).' },
    { id: 'sb_3', q: 'What does initialData do for StreamBuilder?', a: 'Provides a value before the first stream emission — skipping the spinner flash when you already have cached data. The snapshot starts with data instead of waiting.' },
    { id: 'sb_4', q: 'When do you graduate from builders to BLoC/Riverpod?', a: 'When the screen also MUTATES (create/edit/delete with loading and errors per action), needs retries/optimistic updates, or multiple widgets share the async state. Builders are for read-only display.' },
    { id: 'sb_5', q: 'What is StreamBuilder under the hood?', a: 'A StatefulWidget that subscribes in initState/didUpdateWidget, calls setState on each event, and cancels in dispose — ~30 lines you could write yourself. AsyncValue/BlocBuilder are the same pattern with better state modeling.' },
  ],
  'unit-testing-flutter': [
    { id: 'ut_1', q: 'How does DI enable unit testing?', a: "Classes receive dependencies via constructors, so tests inject fakes/mocks: AuthBloc(MockAuthService()) tests every logic path in milliseconds with zero network. Classes that new-up dependencies internally can't be isolated." },
    { id: 'ut_2', q: 'What does blocTest verify?', a: 'The full state machine declaratively: build the bloc (with mocks), act (add events), expect (the exact sequence of emitted states), verify (dependency interactions). Event-in → states-out as data.' },
    { id: 'ut_3', q: 'Mock vs fake vs stub?', a: 'Stub: returns canned answers. Mock: stub + records calls for verification (mocktail). Fake: a working lightweight implementation (in-memory repository). Use fakes for complex collaborators, mocks for verification.' },
    { id: 'ut_4', q: 'What makes a test brittle?', a: "Asserting implementation details (internal call order, private state) instead of behavior — refactors break it while bugs don't. Test inputs → outputs/states, verify only meaningful interactions." },
    { id: 'ut_5', q: 'How do you test stream emissions?', a: 'expect(stream, emitsInOrder([a, b, emitsError(isA<X>())])) — set the expectation, then trigger. For blocs, blocTest handles the subscription dance for you.' },
  ],
  'widget-testing': [
    { id: 'wt_1', q: 'pump vs pumpAndSettle?', a: 'pump(): advance one frame (optionally a duration). pumpAndSettle(): pump until no frames are scheduled — completes animations, but HANGS forever on infinite animations (spinners). Use bounded pumps with those.' },
    { id: 'wt_2', q: 'How do you provide mocked blocs in widget tests?', a: 'Same DI as production: pumpWidget(MaterialApp(home: BlocProvider.value(value: mockBloc, child: LoginView()))). whenListen (bloc_test) stubs the state stream the widget sees.' },
    { id: 'wt_3', q: 'find.byKey vs find.text?', a: 'byKey survives copy changes and localization — use Keys for actionable elements (buttons, fields). find.text couples tests to wording; reserve it for asserting user-visible messages.' },
    { id: 'wt_4', q: 'What are golden tests?', a: "Pixel-snapshot comparisons: expect(finder, matchesGoldenFile('card.png')). Excellent regression nets for design-system components; brittle for full screens (fonts/platforms shift pixels)." },
    { id: 'wt_5', q: "What's the highest-value widget test pattern?", a: 'State-to-UI mapping: mock the bloc, emit each state, assert what renders — loading shows spinner, failure shows the dialog, empty shows the CTA. One test per meaningful state.' },
  ],
  'integration-testing': [
    { id: 'it_1', q: 'What belongs at each test pyramid level?', a: 'Many unit tests (logic: blocs, services), some widget tests (per-screen behavior), FEW integration tests (3-5 critical end-to-end journeys on devices). Inverting it produces slow, flaky suites.' },
    { id: 'it_2', q: 'How do you make integration tests hermetic with Firebase?', a: 'Firebase Emulator Suite: useAuthEmulator/useFirestoreEmulator point the app at local emulators — no prod data, no costs, resettable state, and rules testable locally.' },
    { id: 'it_3', q: 'How do you fight device-test flakiness?', a: 'No arbitrary sleeps — pump until finders appear; unique per-run test accounts (timestamped emails); reset state between tests; explicit waits on conditions, not durations.' },
    { id: 'it_4', q: 'Which journeys deserve integration tests?', a: 'The flows where breakage loses users: register→verify→login, the core CRUD loop, checkout/payment, logout. Everything narrower belongs lower in the pyramid.' },
    { id: 'it_5', q: 'What extra can Patrol do?', a: "Native interactions plain integration_test can't touch: permission dialogs, notifications, device settings — the OS-level steps in real user journeys." },
  ],
  'tdd-bdd-flutter': [
    { id: 'td_1', q: 'Walk through one red-green-refactor cycle.', a: 'RED: write a failing test naming the next behavior (blocTest expecting [Loading, Loaded]). GREEN: minimal code to pass — no gold-plating. REFACTOR: clean code AND tests while everything stays green. Repeat.' },
    { id: 'td_2', q: "What is TDD's \"design pressure\"?", a: "Untestable design hurts at step 1 instead of testing-week: hidden dependencies, god-classes, and static singletons make the first test hard to write — forcing better architecture immediately." },
    { id: 'td_3', q: 'Where does TDD fit poorly in Flutter?', a: 'Exploratory UI work — pixel-pushing has no spec to test yet. TDD the logic layers; iterate UI visually; backfill widget tests once behavior settles.' },
    { id: 'td_4', q: 'What two TDD-ish rules give 80% of the value?', a: 'Every new bloc handler starts with a failing blocTest; every bug fix starts with a failing reproduction test. The second rule makes every fixed bug extinct forever.' },
    { id: 'td_5', q: 'What is BDD and when does it pay?', a: 'Specs as behaviors: Given/When/Then readable by non-engineers (gherkin/.feature files generating tests). The ceremony pays when stakeholders actually read the specs; otherwise plain well-named tests suffice.' },
  ],
  'error-handling-flutter': [
    { id: 'eh_1', q: 'Trace a failed Firestore write to what the user sees.', a: 'Service catches FirebaseException → throws typed NetworkException with userMessage → bloc catches, emits NotesFailure(message, retryEvent) → UI renders the message with a working Retry button. Raw errors never surface.' },
    { id: 'eh_2', q: 'Expected vs unexpected errors — different handling?', a: 'Expected (wrong password, offline): typed, caught, rendered with recovery actions. Unexpected (bugs): global handlers → crash reporting → generic apology UI. Designing for both is the architecture.' },
    { id: 'eh_3', q: "Why is catch (e) { print(e); } the worst pattern?", a: "The error black hole: user sees nothing happen, you get no report, the bug ships silently. Every catch must render, report, or rethrow — never just log to a console nobody reads." },
    { id: 'eh_4', q: 'Typed exceptions vs Result/Either types?', a: 'Typed exceptions: idiomatic Dart, invisible in signatures (can be forgotten). Result<T>/Either: failures explicit in return types, compile-enforced handling — heavier syntax. Both work; pick one and be consistent.' },
    { id: 'eh_5', q: 'Which errors should auto-retry?', a: 'Transient + idempotent: network timeouts on GETs, with exponential backoff and a cap. Never auto-retry non-idempotent writes (duplicates) or 4xx (the request itself is wrong).' },
  ],
  'linting-code-quality': [
    { id: 'lq_1', q: 'Which two lints catch real crash classes?', a: 'unawaited_futures: every unawaited async call is intentional (wrap in unawaited()) or a bug. use_build_context_synchronously: statically catches using context after await without a mounted check.' },
    { id: 'lq_2', q: 'How do you introduce strict linting to a legacy codebase?', a: 'Gradually: flutter_lints baseline first, then enable one stricter rule per week with dart fix --apply doing bulk work. Enabling everything at once → 3000 warnings → team ignores ALL warnings.' },
    { id: 'lq_3', q: 'What is the minimum CI quality gate?', a: 'dart format --set-exit-if-changed (style settled by machine), flutter analyze (zero issues), flutter test. Every PR, blocking merge. Humans then review design, not commas.' },
    { id: 'lq_4', q: 'What does dart fix do?', a: 'Auto-applies fixes for many lint violations and deprecations: --dry-run previews, --apply executes. The bulk-work tool when tightening rules on existing code.' },
    { id: 'lq_5', q: 'Why require justification on // ignore: comments?', a: "Unjustified ignores erode rules silently — six months later nobody knows if they're load-bearing. An ignore with a reason is auditable; without one it's technical debt in disguise." },
  ],
  'app-icons-splash': [
    { id: 'ais_1', q: 'How do Android adaptive icons work?', a: 'Two layers — background + foreground — that the OS masks into circles/squircles per launcher and animates. Keep critical content in the inner 66% safe zone or it gets clipped on round masks.' },
    { id: 'ais_2', q: 'Why does the native splash exist separately from Flutter loading screens?', a: "The OS shows the native splash BEFORE the Flutter engine boots — Flutter can't draw yet. flutter_native_splash configures that OS layer; any animated branded loading after engine start is a separate Flutter screen." },
    { id: 'ais_3', q: 'What causes the "double splash" jump?', a: "Native splash background differing from your app's first frame — a visible color snap at engine handoff. Match them exactly for a seamless launch." },
    { id: 'ais_4', q: 'Which identifiers are immutable after first release?', a: 'applicationId (Android) and bundle ID (iOS) — changing them creates a new store listing. The display name CAN change; the identifiers cannot.' },
    { id: 'ais_5', q: 'What tools automate icons and splash?', a: 'flutter_launcher_icons (one 1024px master → all densities + adaptive layers) and flutter_native_splash (Android 12+ themed splash + iOS storyboard) — two pubspec blocks replacing ~40 hand-cropped files.' },
  ],
  'localization-flutter': [
    { id: 'l10_1', q: 'How does the gen-l10n pipeline work?', a: 'ARB files (app_en.arb template + per-language) hold strings with metadata → flutter gen-l10n generates a typed AppLocalizations class → MaterialApp wires delegates/supportedLocales → context access: l10n.welcomeUser(name).' },
    { id: 'l10_2', q: 'How do ICU plurals handle complex languages?', a: "{count, plural, =0{No notes} one{1 note} other{{count} notes}} — each language's ARB provides its own plural forms (some need few/many), and the runtime picks correctly per locale. Never concatenate counts manually." },
    { id: 'l10_3', q: 'What habit makes RTL support nearly free?', a: 'Directional values everywhere: EdgeInsetsDirectional.only(start:) instead of left:, Alignment.centerStart instead of centerLeft. Layouts then mirror automatically for Arabic/Hebrew via Directionality.' },
    { id: 'l10_4', q: 'Why is string concatenation a localization bug?', a: '"You have " + n + " notes" hardcodes English word order — other languages order differently and have multiple plural forms. Placeholders and ICU plurals exist precisely for this.' },
    { id: 'l10_5', q: 'Why test with German or pseudo-locales?', a: 'German strings run 30-40% longer than English — tight layouts truncate or overflow. Pseudo-localization (elongated accented text) catches these breaks before paying translators.' },
  ],
  'android-release': [
    { id: 'ar_1', q: 'Upload key vs app signing key under Play App Signing?', a: "Google holds the APP signing key (signs what users install); your keystore is just the UPLOAD key (authenticates uploads). Lose the upload key → support ticket reset. Without enrollment, a lost key = permanent lockout." },
    { id: 'ar_2', q: 'What is a staged rollout?', a: 'Releasing to 5% → 20% → 100% of users with monitoring between stages and a HALT button. A catastrophic bug becomes a contained incident affecting 5%, not ten thousand one-star reviews.' },
    { id: 'ar_3', q: 'Why can release builds crash when debug worked?', a: "R8 minification strips/renames code that reflection-using plugins need — debug doesn't minify. Always smoke-test the actual release build (flutter install --release); add ProGuard keep rules when needed." },
    { id: 'ar_4', q: 'What do versionCode and versionName mean in version: 1.2.0+7?', a: 'versionName 1.2.0: human-readable display. versionCode 7: integer that MUST increase on every upload — Play rejects uploads with a reused or lower code.' },
    { id: 'ar_5', q: 'What does the Data Safety form require?', a: 'Accurate declaration of what data the app collects and why — INCLUDING what your SDKs collect (Firebase Analytics gathers identifiers). Contradicting actual behavior risks rejection or later takedown.' },
  ],
  'ios-release': [
    { id: 'ir_1', q: 'Walk through zero-to-App-Store.', a: 'Developer Program ($99/yr) → Xcode automatic signing + bundle ID → flutter build ipa → upload (Transporter/Xcode) → TestFlight testing → listing + privacy labels + screenshots → submit with review notes → human review (~1-2 days) → release.' },
    { id: 'ir_2', q: 'Top App Store rejection reasons?', a: 'Crashes on launch (test release on real devices), missing demo account for login-gated apps, social login without Sign in with Apple, digital purchases bypassing IAP, broken links, inaccurate privacy labels.' },
    { id: 'ir_3', q: 'What is TestFlight?', a: "Apple's beta channel: internal testers (team, instant) and external (up to 10K, light beta review). Builds expire in 90 days. External beta is a soft preview of full review — use it before first submission." },
    { id: 'ir_4', q: 'What are privacy nutrition labels?', a: "The App Store's data-collection disclosure grid — every data type your app and SDKs collect, linked or not linked to identity, used for tracking or not. Must match real SDK behavior." },
    { id: 'ir_5', q: 'How should you respond to a rejection?', a: "It's a normal lifecycle event: read the cited guideline, reply or fix in Resolution Center, resubmit. The course itself gets rejected (security rules) and resubmits — everyone iterates." },
  ],
  'cicd-flutter': [
    { id: 'ci_1', q: 'Design a Flutter CI/CD pipeline.', a: 'Per PR: checkout → pinned Flutter → format check → analyze → test → debug build (the quality gate, branch-protected). Per release tag: decode signing secrets → build signed AAB/IPA with obfuscation → upload symbols → deploy to tracks/TestFlight. Merges to main → Firebase App Distribution for testers.' },
    { id: 'ci_2', q: 'How do signing secrets live in CI safely?', a: 'Keystore/certs base64-encoded into repo secrets, decoded to files during the job, never logged, never committed. --dart-define values injected from secrets the same way.' },
    { id: 'ci_3', q: 'What does Fastlane match solve?', a: 'iOS team signing hell: certificates and provisioning profiles stored in an encrypted repo, synced identically to every developer machine and CI runner — no more "works on my Mac" signing.' },
    { id: 'ci_4', q: 'Why pin the Flutter version in CI?', a: 'Unpinned CI tracks the latest stable — builds break the day a new Flutter releases, unrelated to your changes. Pin (and FVM-match locally) so upgrades are deliberate, tested events.' },
    { id: 'ci_5', q: 'Where should build numbers come from?', a: 'CI: --build-number=${{ github.run_number }} or derived from the git tag — monotonically increasing, traceable to the exact commit, and never hand-bumped (or forgotten) again.' },
  ],
  'analytics-crashlytics': [
    { id: 'ac_1', q: 'Wire complete crash reporting — what are the pieces?', a: 'FlutterError.onError → recordFlutterFatalError (framework errors) AND PlatformDispatcher.onError → recordError (uncaught async — most crashes!). Plus symbol upload in CI for obfuscated builds, custom keys for context, velocity alerts on.' },
    { id: 'ac_2', q: 'Why upload symbol files?', a: 'Obfuscated release builds (--obfuscate --split-debug-info) produce unreadable hex stacks. Uploading the symbols to Crashlytics symbolicates them back to file/line — without it, crashes are undiagnosable.' },
    { id: 'ac_3', q: 'How do you design an analytics taxonomy that stays useful?', a: 'Small and governed: 10-20 events documented (name, params, trigger, owner) BEFORE coding, consistent naming (note_created), no PII in params, and event changes reviewed in PRs like schema changes.' },
    { id: 'ac_4', q: 'A crash spike hits during a staged rollout — response?', a: 'HALT the rollout (the staging payoff), read the symbolicated stack + custom keys (which screen/flag), reproduce, write the failing test, fix, ship through the same gates, resume staged rollout watching velocity.' },
    { id: 'ac_5', q: 'What is crash-free rate and a healthy target?', a: 'Percentage of sessions without crashes — the headline production health metric. >99.5% is the common bar; Play additionally demotes poor-vitals apps in search.' },
  ],
  'store-guidelines': [
    { id: 'sg_1', q: 'When must you use in-app purchases vs external payments?', a: 'Digital goods/subscriptions consumed in-app: IAP required (Apple 3.1.1 / Play Billing, 15-30% commission). Physical goods and real-world services (rides, food): external payments fine — the Uber rule.' },
    { id: 'sg_2', q: 'What ongoing obligations come with a published Play app?', a: 'The annual target-API ratchet (must target a recent Android API or face delisting), policy form updates, vitals monitoring (ANR/crash rates affect ranking), and re-review on every update.' },
    { id: 'sg_3', q: 'What account rule do both stores now enforce?', a: 'Apps with account creation MUST offer in-app account DELETION (not just a support email) — cascading the auth user and their data. Design it with the account system, not after rejection.' },
    { id: 'sg_4', q: 'Why use RevenueCat for subscriptions?', a: 'It handles the genuinely hard parts: receipt validation, cross-platform entitlements (iOS purchase unlocks Android), restore flows, and policy-correct subscription management — a solved category.' },
    { id: 'sg_5', q: 'Can a previously-approved feature be rejected later?', a: 'Yes — full review re-runs on EVERY update, and policies evolve. A two-year-old feature can be newly flagged. Budget for compliance maintenance, not just feature work.' },
  ],
  'flutter-career': [
    { id: 'fc_1', q: 'What does the Flutter interview canon cover?', a: 'The three trees + keys, StatefulWidget lifecycle, the constraint model, your state management deep + fair comparisons, async/isolates, and one system design ("architect a chat app") assembling all of it aloud.' },
    { id: 'fc_2', q: 'What makes a portfolio actually convert?', a: 'SHIPPED store apps (store links beat repo links — shipping proves the hard last 20%), one architecture-showcase repo (tests, CI badge, README explaining decisions), and war stories from real release/review battles.' },
    { id: 'fc_3', q: 'Why do shipped apps outweigh tutorial clones?', a: "Reviewers recognize course apps instantly. One original app with a Play Store link, Crashlytics dashboard, and review scars demonstrates the production skills tutorials can't — judgment, persistence, and ownership." },
    { id: 'fc_4', q: 'How should you answer "why Flutter over native"?', a: "With trade-offs both ways: one codebase/velocity/consistent UI vs platform-API lag and ecosystem dependency — then tie to the product's actual needs. Tribal answers fail; judgment answers hire." },
    { id: 'fc_5', q: 'What adjacent skills compound a Flutter career?', a: 'Native basics (Kotlin/Swift — debug platform issues, write channels), backend development (full-stack mobile engineers are rare and prized), and Firebase depth. Tell decisions and incidents in interviews, not definitions.' },
  ],
}
